    private static string BuildWhereClause(IQueryCollection queryParams)
    {
        var conditions = new List<string>();

        foreach (var param in queryParams)
        {
            if (param.Key == "table" || param.Key == "columns" || param.Key == "orderBy" || param.Key == "limit")
                continue;

            string key = param.Key;
            string value = param.Value.ToString();

            if (key.EndsWith("_gt"))
            {
                string column = key.Replace("_gt", "");
                conditions.Add($"{column} > {value}");
            }
            else if (key.EndsWith("_lt"))
            {
                string column = key.Replace("_lt", "");
                conditions.Add($"{column} < {value}");
            }
            else if (key.EndsWith("_gte"))
            {
                string column = key.Replace("_gte", "");
                conditions.Add($"{column} >= {value}");
            }
            else if (key.EndsWith("_lte"))
            {
                string column = key.Replace("_lte", "");
                conditions.Add($"{column} <= {value}");
            }
            else if (key.EndsWith("_like"))
            {
                string column = key.Replace("_like", "");
                conditions.Add($"{column} LIKE '%{value}%'");
            }
            else if (key.EndsWith("_in"))
            {
                string column = key.Replace("_in", "");
                conditions.Add($"{column} IN ({value})");
            }
            else
            {
                if (IsNumeric(value))
                {
                    conditions.Add($"{key} = {value}");
                }
                else
                {
                    conditions.Add($"{key} = '{value}'");
                }
            }
        }

        return string.Join(" AND ", conditions);
    }

    private static bool IsNumeric(string value)
    {
        return double.TryParse(value, out _);
    }
}

